/**
 * SVG Icon library — Heroicons/Lucide style stroke icons
 * Foydalanish: <?= icon('home') ?>  yoki  <?= icon('home', 24, 'my-class') ?>
 */

function icon(string $name, int $size = 20, string $class = ''): string {
    static $icons = null;
    if ($icons === null) $icons = _icons_data();

    $svg = $icons[$name] ?? $icons['_missing'];
    $cls = trim('icon icon-'.$name.' '.$class);
    return str_replace(
        '<svg ',
        '<svg width="'.$size.'" height="'.$size.'" class="'.htmlspecialchars($cls, ENT_QUOTES).'" ',
        $svg
    );
}

